// Temas rotativos: se elige según la semana ISO + día (martes/jueves) para no repetir seguido.
const temas = [
  { label: 'Capacitación con realidad virtual en minería (Chile)', query: 'capacitacion realidad virtual mineria' },
  { label: 'Realidad virtual y XR en Chile', query: 'realidad virtual Chile empresas' },
  { label: 'Videos 3D y simulación para minería e industria', query: 'simulacion 3D animacion industria mineria' },
  { label: 'Realidad aumentada en la industria', query: 'realidad aumentada industria mantenimiento' },
  { label: 'Hardware XR: visores, chips y lentes inteligentes', query: 'visores realidad virtual chip XR' },
  { label: 'IA aplicada a XR y entrenamiento industrial', query: 'inteligencia artificial realidad virtual entrenamiento' },
  { label: 'Gemelos digitales en minería e industria', query: 'gemelo digital mineria industria' },
  { label: 'Seguridad minera y nuevas tecnologías', query: 'seguridad minera tecnologia capacitacion' },
];
const now = new Date();
const start = new Date(Date.UTC(now.getUTCFullYear(), 0, 1));
const week = Math.floor(((now - start) / 86400000 + start.getUTCDay() + 1) / 7);
const slot = now.getDay() === 4 ? 1 : 0; // jueves=1, cualquier otro día=0
const tema = temas[(week * 2 + slot) % temas.length];
const rssUrl = 'https://www.bing.com/news/search?q=' + encodeURIComponent(tema.query) + '&format=RSS&mkt=es-CL';
return [{ json: { tema: tema.label, query: tema.query, rssUrl } }];

// Parsea el RSS de Bing News y arma la petición para DeepSeek.
const xml = $json.data || '';
const decode = (s) => (s || '')
  .replace(/<!\[CDATA\[([\s\S]*?)\]\]>/g, '$1')
  .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"').replace(/&#39;|&apos;/g, "'").trim();

const todas = [];
const items = xml.match(/<item>[\s\S]*?<\/item>/g) || [];
for (const it of items) {
  const title = decode((it.match(/<title>([\s\S]*?)<\/title>/) || [])[1]);
  let link = decode((it.match(/<link>([\s\S]*?)<\/link>/) || [])[1]);
  const pub = decode((it.match(/<pubDate>([\s\S]*?)<\/pubDate>/) || [])[1]);
  // Bing envuelve la URL real en apiclick.aspx?...url=<encoded>
  const m = link.match(/[?&]url=([^&]+)/);
  if (m) link = decodeURIComponent(m[1]);
  if (!title || !link || /bing\.com/i.test(link)) continue;
  const d = new Date(pub);
  let fuente = '';
  try { fuente = new URL(link).hostname.replace(/^www\./, ''); } catch (e) {}
  if (!todas.some(n => n.link === link)) todas.push({ title, link, fuente, ts: isNaN(d) ? 0 : d.getTime(), fecha: isNaN(d) ? '' : d.toISOString().slice(0, 10) });
}
todas.sort((x, y) => y.ts - x.ts);
// Solo noticias de los últimos 7 días. Si no hay ninguna, el prompt indica escribir un artículo evergreen sin citas.
const noticias = todas.filter(n => n.ts && (Date.now() - n.ts) <= 7 * 86400000).slice(0, 8);

const fecha = new Date().toLocaleDateString('es-CL', { year: 'numeric', month: 'long', day: 'numeric' });
const listado = noticias.length
  ? noticias.map((n, i) => (i + 1) + '. ' + n.title + ' | ' + n.fuente + ' | ' + n.link + (n.fecha ? ' | ' + n.fecha : '')).join('\n')
  : '(No hay noticias disponibles hoy: escribe un artículo educativo/evergreen sobre el tema, SIN citar fuentes externas ni inventar URLs.)';

const system = [
'Eres el redactor senior de contenidos SEO del blog de Doble 3D Studio (doble3d.cl), estudio chileno especializado en: capacitación con realidad virtual para minería e industrias de alto riesgo, videos y animación 3D técnica, realidad aumentada, aplicaciones WebGL, y CORE (plataforma propia de gestión y métricas de entrenamiento inmersivo, integrable a los LMS del cliente). Clientes destacados: Codelco, Minera Centinela, FlyWithUs y FLS (FLSmidth). Diferenciales: desarrollo a medida en Chile, integración con las plataformas que el cliente ya usa (LMS/SCORM) y soporte postventa perpetuo.',
'',
'Escribes en español chileno neutro y profesional. Cuando hablas de Doble 3D usas primera persona plural ("En Doble 3D creemos...").',
'',
'ENLACES INTERNOS disponibles (integra 2 o 3 de forma natural y contextual dentro del cuerpo, con anchor text descriptivo):',
'- https://doble3d.cl/servicios/realidad-virtual/ (capacitación VR industrial/minería)',
'- https://doble3d.cl/servicios/animacion-3d/ (videos y animación 3D técnica)',
'- https://doble3d.cl/servicios/core/ (plataforma CORE)',
'- https://doble3d.cl/servicios/gamificacion-scorm/ (apps gamificadas SCORM)',
'- https://doble3d.cl/app-webgl/ (aplicaciones WebGL)',
'',
'ESTRUCTURA OBLIGATORIA de content_html (NO incluyas H1, el título va aparte; NO incluyas los bloques de cierre, se agregan automáticamente):',
'1) Un párrafo inicial de 60 a 90 palabras que resuma la noticia con datos concretos y contenga la focus keyword de forma natural (respuesta directa, optimizada para motores de respuesta/AEO).',
'2) De 3 a 5 secciones <h2> (al menos dos formuladas como pregunta), con párrafos <p> de 2 a 4 oraciones. Cita cada medio con <a href="URL" target="_blank" rel="noopener">nombre del medio</a>. USA SOLO las URLs de la lista de noticias entregada; está PROHIBIDO inventar URLs externas.',
'3) Una sección que conecte la noticia con el trabajo de Doble 3D en minería/industria chilena (aporte de valor, sin venta dura).',
'4) Al final: <h2>Preguntas frecuentes</h2> con exactamente 4 bloques de <h3>(pregunta)</h3> seguido de <p>(respuesta de 40 a 60 palabras, autocontenida, con entidades y cifras)</p>. Las mismas 4 preguntas/respuestas van en el array faq.',
'',
'REGLAS SEO (Yoast): focus_keyword long-tail en minúsculas y sin tildes (ej: "capacitacion realidad virtual mineria"); la keyword aparece en el primer párrafo, en al menos un H2 y en el slug; meta_title de máximo 60 caracteres comenzando con la keyword o muy cerca del inicio; meta_description de 120 a 155 caracteres con la keyword y un llamado a la acción; slug corto de 3 a 6 palabras; excerpt de 1 a 2 oraciones. Artículo de 800 a 1200 palabras.',
'',
'REGLAS AEO/LLMs: respuestas directas y autocontenidas, cifras y datos concretos, nombres completos de empresas y tecnologías, lenguaje declarativo y verificable.',
'',
'RESPONDE ÚNICAMENTE un objeto JSON válido con estas claves exactas:',
'{',
'  "titulo": "máx 65 caracteres, atractivo, incluye la keyword o parte de ella",',
'  "subtitulo_imagen": "máx 60 caracteres, complementa al título sin repetirlo",',
'  "tag_top": "etiqueta de categoría para la imagen, máx 30 caracteres, MAYÚSCULAS, ej: CAPACITACIÓN INMERSIVA INDUSTRIAL",',
'  "tag_1": "primera entidad clave de la noticia, máx 16 caracteres, ej: CODELCO o QUALCOMM",',
'  "tag_2": "segunda entidad o tecnología clave, máx 16 caracteres, ej: AULA 4.0 o 48 TOPS",',
'  "slug": "en-minusculas-con-guiones",',
'  "meta_title": "máx 60 caracteres",',
'  "meta_description": "120 a 155 caracteres",',
'  "focus_keyword": "keyword long-tail",',
'  "excerpt": "1-2 oraciones",',
'  "categoria": "UNA de: Realidad Virtual en minería | Realidad Virtual | Videos 3D Minería | Realidad Mixta | Inteligencia Artificial | Innovación | Tecnología | WebGL en minería",',
'  "tags": ["3 a 5 tags en español"],',
'  "content_html": "el cuerpo HTML según la estructura",',
'  "faq": [{"q": "pregunta", "a": "respuesta en texto plano"}] // exactamente 4',
'}'
].join('\n');

const user = 'Fecha de hoy: ' + fecha + '.\nTema del día: ' + $('Elegir tema').item.json.tema + '.\n\nNoticias recientes encontradas (elige la más relevante para el tema y el negocio de Doble 3D; puedes apoyarte en 2 o 3 relacionadas como contexto secundario):\n\n' + listado + '\n\nEscribe el artículo siguiendo todas las reglas y responde solo el JSON.';

return [{ json: {
  noticiasEncontradas: noticias.length,
  body: {
    model: 'deepseek-v4-pro',
    messages: [ { role: 'system', content: system }, { role: 'user', content: user } ],
    response_format: { type: 'json_object' },
    temperature: 0.7,
    max_tokens: 12000,
    thinking: { type: 'disabled' },
  },
} }];

// Parsea la respuesta de DeepSeek, valida SEO, resuelve tags en WP y arma el post final.
const STATUS = 'publish'; // 'publish' = publicación automática | 'draft' = borrador para revisar
const WP = 'https://doble3d.cl/wp-json/wp/v2';
const AUTH = { Authorization: 'Basic WORDPRESS_APP_PASSWORD_REDACTED' };

const choice = ($json.choices && $json.choices[0]) || {};
const finishReason = choice.finish_reason || '?';
let raw = (choice.message && choice.message.content) || '';
raw = raw.replace(/^\s*```(?:json)?/i, '').replace(/```\s*$/i, '').trim();
// Aislar el objeto JSON por si el modelo añade texto alrededor
const ini = raw.indexOf('{'); const fin = raw.lastIndexOf('}');
if (ini >= 0 && fin > ini) raw = raw.slice(ini, fin + 1);
let a;
try { a = JSON.parse(raw); } catch (e) {
  throw new Error('DeepSeek no devolvió JSON válido (finish_reason=' + finishReason + ', ' + raw.length + ' chars). Inicio: ' + raw.slice(0, 200) + ' ... Final: ' + raw.slice(-200));
}

for (const k of ['titulo', 'slug', 'meta_title', 'meta_description', 'focus_keyword', 'content_html']) {
  if (!a[k] || typeof a[k] !== 'string') throw new Error('Falta el campo "' + k + '" en la respuesta de DeepSeek');
}
if (!Array.isArray(a.faq) || a.faq.length < 3) throw new Error('FAQ incompleta en la respuesta de DeepSeek');

const trunc = (s, n) => s.length <= n ? s : s.slice(0, n).replace(/\s+\S*$/, '');
const metaTitle = trunc(a.meta_title.trim(), 60);
const metaDesc = trunc(a.meta_description.trim(), 155);
const slug = a.slug.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '').split('-').slice(0, 8).join('-');

const CATS = { 'realidad virtual en minería': 14, 'realidad virtual en mineria': 14, 'realidad virtual': 39, 'videos 3d minería': 1, 'videos 3d mineria': 1, 'realidad mixta': 15, 'inteligencia artificial': 32, 'innovación': 61, 'innovacion': 61, 'tecnología': 52, 'tecnologia': 52, 'webgl en minería': 17, 'webgl en mineria': 17 };
const catId = CATS[(a.categoria || '').toLowerCase().trim()] || 39;

// Resolver tags: buscar cada uno en WP, crear los que no existan.
const tagIds = [];
for (const nombre of (a.tags || []).slice(0, 5)) {
  const name = String(nombre).trim();
  if (!name) continue;
  try {
    const found = await this.helpers.httpRequest({ method: 'GET', url: WP + '/tags', qs: { search: name, per_page: 10 }, headers: AUTH, json: true });
    const exact = (found || []).find(t => t.name.toLowerCase() === name.toLowerCase());
    if (exact) { tagIds.push(exact.id); continue; }
    const created = await this.helpers.httpRequest({ method: 'POST', url: WP + '/tags', body: { name }, headers: AUTH, json: true });
    if (created && created.id) tagIds.push(created.id);
  } catch (e) { /* un tag fallido no detiene la publicación */ }
}

// Schema JSON-LD FAQPage (AEO) a partir del array faq.
const clean = (s) => String(s || '').replace(/<[^>]*>/g, '').trim();
const faqLd = {
  '@context': 'https://schema.org',
  '@type': 'FAQPage',
  mainEntity: a.faq.slice(0, 6).map(f => ({
    '@type': 'Question', name: clean(f.q),
    acceptedAnswer: { '@type': 'Answer', text: clean(f.a) },
  })),
};

// Bloques fijos de cierre (enlaces internos + CTA), como en los templates.
const bloqueCierre = [
'<h2>Para profundizar en capacitación VR para minería</h2>',
'<ul>',
'<li><a href="https://doble3d.cl/servicios/realidad-virtual/">Realidad virtual industrial para entrenamiento en minería</a></li>',
'<li><a href="https://doble3d.cl/servicios/animacion-3d/">Animación 3D técnica para procesos industriales</a></li>',
'<li><a href="https://doble3d.cl/servicios/gamificacion-scorm/">Apps gamificadas con SCORM para entrenamiento industrial</a></li>',
'</ul>',
'<p>En Doble 3D desarrollamos <a href="https://doble3d.cl/servicios/realidad-virtual/">capacitación en realidad virtual</a> para faenas mineras tier-1 como Codelco, Minera Centinela y FlyWithUs, y <a href="https://doble3d.cl/servicios/animacion-3d/">videos 3D para minería</a> para clientes como FLS (FLSmidth). Centraliza y mide tu entrenamiento inmersivo con <a href="https://doble3d.cl/servicios/core/">CORE</a>.</p>',
'<h2>¿Quieres llevar la capacitación inmersiva industrial a tu operación?</h2>',
'<p>En Doble 3D Studio diseñamos experiencias inmersivas a medida para minería e industrias de alto riesgo, integradas a las plataformas que ya usas, con soporte postventa perpetuo.</p>',
'<p>👉 <a href="https://wa.me/56958015971" target="_blank" rel="noopener">Conversemos por WhatsApp</a><br>🌐 <a href="https://doble3d.cl/servicios/">Conoce más</a></p>',
'<script type="application/ld+json">' + JSON.stringify(faqLd) + '</script>',
].join('\n');

const subt = (a.subtitulo_imagen || a.focus_keyword || '').slice(0, 60);
const tagTop = (a.tag_top || 'CAPACITACIÓN INMERSIVA INDUSTRIAL').slice(0, 32);
const tag1 = (a.tag_1 || 'DOBLE 3D').slice(0, 18);
const tag2 = (a.tag_2 || 'VR INDUSTRIAL').slice(0, 18);

return [{ json: {
  status: STATUS,
  titulo: a.titulo.trim(),
  slug,
  metaTitle,
  metaDesc,
  focusKeyword: a.focus_keyword.trim(),
  excerpt: (a.excerpt || metaDesc).trim(),
  categoria: catId,
  tagIds,
  content: a.content_html.trim() + '\n' + bloqueCierre,
  imageUrl: 'https://doble3d.cl/image-gen.php?titulo=' + encodeURIComponent(a.titulo.trim()) + '&subtitulo=' + encodeURIComponent(subt) + '&tag_top=' + encodeURIComponent(tagTop) + '&tag_1=' + encodeURIComponent(tag1) + '&tag_2=' + encodeURIComponent(tag2),
  filename: slug + '.webp',
} }];

parameters.jsonBody:
={{ JSON.stringify({
  title: $('Ensamblar post').item.json.titulo,
  slug: $('Ensamblar post').item.json.slug,
  status: $('Ensamblar post').item.json.status,
  content: $('Ensamblar post').item.json.content,
  excerpt: $('Ensamblar post').item.json.excerpt,
  categories: [$('Ensamblar post').item.json.categoria],
  tags: $('Ensamblar post').item.json.tagIds,
  featured_media: $json.id,
  meta: {
    _yoast_wpseo_title: $('Ensamblar post').item.json.metaTitle,
    _yoast_wpseo_metadesc: $('Ensamblar post').item.json.metaDesc,
    _yoast_wpseo_focuskw: $('Ensamblar post').item.json.focusKeyword
  }
}) }}
